To change the player movement script so that the left and right arrow keys turn the cube instead of moving it to the sides, we'll need to modify the rotation of the cube. Here's an example of how you can do this using Unity:

```csharp
using System.Collections;
using System.Collections.Generic;
using UnityEngine;

public class PlayerController : MonoBehaviour
{
    public float speed = 5.0f;
    public float turnSpeed = 5.0f;

    private Rigidbody rb;

    void Start()
    {
        rb = GetComponent<Rigidbody>();
    }

    void FixedUpdate()
    {
        float moveHorizontal = Input.GetAxis("Horizontal");
        float moveVertical = Input.GetAxis("Vertical");

        // Turning the cube
        float turn = Input.GetAxis("Horizontal");

        // Create the turn rotation
        Quaternion turnRotation = Quaternion.Euler(0, turn * turnSpeed, 0);

        // Apply the turn rotation
        transform.rotation = transform.rotation * turnRotation;

        // Moving the cube
        Vector3 movement = new Vector3(moveHorizontal, 0.0f, moveVertical);

        // Apply the movement
        rb.MovePosition(transform.position + movement * speed * Time.deltaTime);
    }
}
```

